/// Maglev — multi-cloud Kubernetes cluster manager
#[derive(Parser)]
#[command(
    name = "maglev",
    version,
    about = "Provision and manage cloud-backed Kubernetes clusters"
)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}
#[derive(Subcommand)]
enum Commands {
    Apply {
        config: String,
        /// Also run the play step after instances are created
        #[arg(long, default_value_t = false)]
        play: bool,
        /// Assume "yes" to every interactive prompt (only meaningful with --play)
        #[arg(long, default_value_t = false)]
        auto_approve: bool,
    },
    Destroy {
        config: String,
    },
    Play {
        config: String,
        #[arg(long, default_value_t = false)]
        auto_approve: bool,
        /// Skip waiting for containerd; fail immediately if it is not ready
        #[arg(long, default_value_t = false)]
        no_wait: bool,
    },
    Reset {
        config: String,
    },
    Restart {
        config: String,
    },
    Print,
}

// ---------------------------------------------------------------------------
// Entry point
// ---------------------------------------------------------------------------

fn main() -> Result<(), Box<dyn std::error::Error>> {
    dotenv::dotenv().ok();
    let cli = Cli::parse();
    match cli.command {
        Commands::Apply {
            config,
            play,
            auto_approve,
        } => apply_config(&config, play, auto_approve),
        Commands::Destroy { config } => destroy_config(&config),
        Commands::Play {
            config,
            auto_approve,
            no_wait,
        } => play_config(&config, auto_approve, no_wait),
        Commands::Reset { config } => reset_config(&config),
        Commands::Restart { config } => restart_config(&config),
        Commands::Print => print_build_credential(),
    }
}

