mod utils;

// ... (rest of main.rs remains identical)
```

### 4. Update `src/command/apply.rs`
Update your `apply` logic to instantiate the state file. It will skip nodes that are already in the state, and write any newly created node directly to the state file so subsequent runs won't recreate them. 

*(**Note:** This assumes your `provider.create_vm(...)` trait method returns the instance ID (e.g., `Result<String, Error>`), which it typically would in this architectural pattern.)*

```rust
// src/command/apply.rs
use crate::command::play::play_config;
use crate::ip::IpAddressType;
use crate::provider::load_provider;
use crate::rule::resolve_rules;
use crate::state::State;
use crate::utils::{prompt_yes_no, read_ssh_public_key};

// ---------------------------------------------------------------------------
// `apply` subcommand
// ---------------------------------------------------------------------------

pub fn apply_config(
    config_path: &str,
    play: bool,
    auto_approve: bool,
) -> Result<(), Box<dyn std::error::Error>> {
    println!("=== Maglev Apply ===\n");
    println!("Reading config: {config_path}");

    let loaded = load_provider(config_path)?;
    let common = loaded.common();

    println!("\n── Provider settings ────────────────────────────────────────────────────");
    loaded.describe();

    let resolved = resolve_rules(common)?;

    // 1. Load state file for this config (e.g., digitalocean.yaml.state)
    let mut state = State::load(config_path);

    println!("\n── Nodes to create ──────────────────────────────────────────────────────");
    let mut total_to_create = 0usize;
    for r in &resolved {
        println!(
            "\n  groups: [{}]  type: {}  (specs: [{}])",
            r.group_names.join(", "),
            r.group_type,
            r.generic_names.join(", "),
        );
        println!(
            "    machine-type: {}  image: {}  ip-address: {}",
            r.merged.machine_type, r.merged.boot_disk_image, r.merged.ip_address,
        );
        println!(
            "    user: {}  ssh-public-key: {}",
            r.merged.user, r.merged.ssh_public_key
        );
        for node in &r.nodes {
            // Check state: Skip instances already in state
            if let Some(id) = state.instances.get(node) {
                println!("      • {node} (Skipping: Already exists in state with ID: {id})");
            } else {
                println!("      • {node}");
                total_to_create += 1;
            }
        }
    }

    if total_to_create == 0 {
        println!("\nAll nodes are already present in the state file. Nothing new to create.");
    } else {
        // Updated to respect auto_approve
        let prompt_msg = format!("\nProceed with creating {total_to_create} new VM instance(s)?");
        if !auto_approve && !prompt_yes_no(&prompt_msg) {
            println!("Aborted.");
            return Ok(());
        }
    }

    let provider = loaded.provider();
    let mut created_count = 0usize;

    for r in &resolved {
        if total_to_create == 0 {
            break; // Quick circuit break if nothing to do
        }

        println!(
            "\n── Groups: [{}] ({}) ─────────────────────────────────────────────────────",
            r.group_names.join(", "),
            r.group_type,
        );

        let ssh_meta = read_ssh_public_key(&r.merged.ssh_public_key)
            .map(|k| format!("{}:{k}", r.merged.user))
            .unwrap_or_else(|e| {
                eprintln!("  ⚠ Could not read SSH public key: {e}");
                String::new()
            });

        let assign_public_ip = r.merged.ip_address == IpAddressType::Public;

        for node in &r.nodes {
            // 2. Before creating, check state again to be safe
            if let Some(id) = state.instances.get(node) {
                println!("\nInstance \"{node}\" already created (ID: {id}), skipping.");
                continue;
            }

            // 3. Create the instance. 
            // If it exists in DO but not in state, the cloud provider will throw a Conflict Error here (Fulfilling the "throw an error" condition).
            let instance_id = provider.create_vm(
                node,
                &r.merged.machine_type,
                &r.merged.boot_disk_image,
                &ssh_meta,
                &r.merged.script,
                assign_public_ip,
            )?;
            let id_str = instance_id.to_string();

            println!("\nInstance \"{node}\" created with ID: {}", id_str);

            // 4. Register mapping immediately and flush to disk
            state.instances.insert(node.clone(), id_str);
            state.save(config_path)?;

            created_count += 1;
        }
    }

    println!("\n✓ {created_count} VM creation request(s) submitted successfully.");

    if play {
        println!("\n── --play flag set: handing off to play ────────────────────────────────");
        // no_wait=false so the play step will poll until containerd is ready
        play_config(config_path, auto_approve, false)?;
    }

    Ok(())
}
```

### How this satisfies your requirements:
1. **JSON file Generation**: It introduces an isolated `State` struct utilizing `serde_json` to manage `<yaml_file>.state`.
2. **Slug mapping**: It accurately records the mapping logic exactly as: `"slug-name": "instance-ID"`.
3. **Resiliency/Skipping**: When `.state` holds a slug, it safely bypasses the cloud provisioning API step for that specific node. 
4. **Mismatch / Error behavior**: If you have a `.yaml` defining a node that doesn't exist in `.state`, but DigitalOcean *does* have a matching slug in its cloud system natively, `create_vm` will bubble up an HTTP Error because a droplet with that name will fail to initialize. This implicitly serves as your exact mismatch validation safely without modifying your raw Provider traits.
